// ../integrations/src/oauth/qwen.ts
import { exec as exec4 } from "node:child_process";
var TOKEN_URL3 = "https://chat.qwen.ai/api/v1/oauth2/token";
var AUTH_URL3 = "https://chat.qwen.ai/login";
var CLIENT_ID4 = "argent-cli";
var POLL_INTERVAL_MS = 5000;
var POLL_TIMEOUT_MS = 300000;
function openBrowser4(url) {
  const platform = process.platform;
  const cmd = platform === "darwin" ? `open "${url}"` : platform === "win32" ? `start "" "${url}"` : `xdg-open "${url}"`;
  exec4(cmd, () => {});
}
function sleep2(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}
async function requestUserCode() {
  const body = new URLSearchParams({
    client_id: CLIENT_ID4
  });
  const res = await fetch("https://chat.qwen.ai/api/v1/oauth2/device/code", {
    method: "POST",
    headers: { "Content-Type": "application/x-www-form-urlencoded" },
    body: body.toString()
  });
  if (!res.ok) {
    const text = await res.text();
    throw new Error(`Failed to request user code (${res.status}): ${text}`);
  }
  const data = await res.json();
  return {
    userCode: data["user_code"],
    deviceCode: data["device_code"],
    verificationUri: data["verification_uri"] ?? AUTH_URL3
  };
}
async function pollForToken(deviceCode) {
  const startTime = Date.now();
  while (Date.now() - startTime < POLL_TIMEOUT_MS) {
    await sleep2(POLL_INTERVAL_MS);
    const body = new URLSearchParams({
      grant_type: "urn:ietf:params:oauth:grant-type:device_code",
      client_id: CLIENT_ID4,
      device_code: deviceCode
    });
    const res = await fetch(TOKEN_URL3, {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body: body.toString()
    });
    if (!res.ok) {
      const data2 = await res.json().catch(() => ({}));
      const error = data2["error"];
      if (error === "authorization_pending")
        continue;
      if (error === "slow_down") {
        await sleep2(POLL_INTERVAL_MS);
        continue;
      }
      if (error === "expired_token") {
        throw new Error("User code expired. Please try again.");
      }
      if (error === "access_denied") {
        throw new Error("User denied the authorization request.");
      }
      throw new Error(`Token poll failed: ${error ?? `HTTP ${res.status}`}`);
    }
    const data = await res.json();
    return {
      accessToken: data["access_token"],
      refreshToken: data["refresh_token"] ?? undefined,
      expiresAt: Math.floor(Date.now() / 1000) + (data["expires_in"] ?? 3600),
      tokenType: data["token_type"] ?? "Bearer",
      scope: data["scope"] ?? undefined,
      provider: "qwen"
    };
  }
  throw new Error("Timed out waiting for Qwen authentication");
}
async function startQwenOAuth(authStore) {
  const { userCode, deviceCode, verificationUri } = await requestUserCode();
  const loginUrl = `${verificationUri}?user_code=${encodeURIComponent(userCode)}`;
  console.log("Qwen Authentication");
  console.log(`Your user code: ${userCode}`);
  console.log(`
Opening browser for sign-in...`);
  console.log(`If the browser doesn't open, visit:
${loginUrl}
`);
  openBrowser4(loginUrl);
  const token = await pollForToken(deviceCode);
  await authStore.setToken("qwen", token);
  console.log("Qwen authentication successful!");
  return token;
}

