// src/cli/commands/diff.ts
import { execSync } from "child_process";
function diffCommand(engine) {
  const lines = [];
  lines.push("");
  lines.push("╔══════════════════════════════════════════╗");
  lines.push("║       Inline Diffs — Pending Changes      ║");
  lines.push("╚══════════════════════════════════════════╝");
  lines.push("");
  const wd = engine.config.getWorkingDir();
  try {
    const output = execSync("git diff --stat", { cwd: wd, encoding: "utf-8", timeout: 1e4 });
    if (!output.trim()) {
      lines.push("  No changes detected in the working tree.");
      return lines.join(`
`);
    }
    const statLines = output.trim().split(`
`);
    const fileChanges = [];
    for (const sl of statLines) {
      const match = sl.match(/^(.+?)\s+\|\s+(\d+)\s+([+-]+)$/);
      if (match) {
        const file = match[1].trim();
        const total = parseInt(match[2], 10);
        const plusMinus = match[3];
        const added = (plusMinus.match(/\+/g) || []).length;
        const removed = (plusMinus.match(/-/g) || []).length;
        fileChanges.push({ file, added, removed, total });
      }
    }
    if (fileChanges.length === 0) {
      lines.push("  No tracked file changes detected.");
      return lines.join(`
`);
    }
    lines.push(`  Changed files: ${fileChanges.length}`);
    lines.push("");
    lines.push(`  ┌${"─".repeat(68)}┐`);
    lines.push(`  │  File                                         +/-    Chgs │`);
    lines.push(`  ├${"─".repeat(68)}┤`);
    for (const fc of fileChanges) {
      const file = fc.file.length > 48 ? "..." + fc.file.slice(-45) : fc.file.padEnd(48, " ");
      const diff = `+${fc.added}/-${fc.removed}`.padEnd(8, " ");
      const chgs = String(fc.total).padStart(4, " ");
      lines.push(`  │ ${file} ${diff}  ${chgs} │`);
    }
    lines.push(`  └${"─".repeat(68)}┘`);
    lines.push("");
    try {
      const diffOutput = execSync("git diff --unified=3", { cwd: wd, encoding: "utf-8", timeout: 1e4, maxBuffer: 100 * 1024 });
      if (diffOutput.trim()) {
        const diffLines = diffOutput.trim().split(`
`).slice(0, 80);
        lines.push("  ── Diff preview (first 80 lines) ──");
        for (const dl of diffLines) {
          if (dl.startsWith("+") && !dl.startsWith("+++")) {
            lines.push(`   + ${dl.slice(1)}`);
          } else if (dl.startsWith("-") && !dl.startsWith("---")) {
            lines.push(`   - ${dl.slice(1)}`);
          } else if (dl.startsWith("@@")) {
            lines.push(`   @ ${dl}`);
          } else if (!dl.startsWith("diff") && !dl.startsWith("index") && !dl.startsWith("---") && !dl.startsWith("+++")) {
            lines.push(`     ${dl}`);
          }
        }
        if (diffLines.length === 80) {
          lines.push("  ... (truncated)");
        }
      }
    } catch {
      lines.push("  (Could not render detail diff)");
    }
  } catch (err) {
    lines.push(`  Error running git diff: ${err instanceof Error ? err.message : String(err)}`);
    lines.push("  Make sure this is a git repository.");
  }
  return lines.join(`
`);
}

// src/cli/commands/review.ts
import { execSync as execSync2 } from "child_process";
function reviewCommand(args, engine) {
  const wd = engine.config.getWorkingDir();
  let statOutput = "";
  try {
    statOutput = execSync2("git diff --stat", { cwd: wd, encoding: "utf-8", timeout: 1e4 });
  } catch {
    return "Not a git repository or git not available.";
  }
  if (!statOutput.trim()) {
    return "No pending changes to review.";
  }
  const subcmd = args[0]?.toLowerCase();
  if (subcmd === "deep" || subcmd === "ai") {
    try {
      const fullDiff = execSync2("git diff", {
        cwd: wd,
        encoding: "utf-8",
        timeout: 1e4,
        maxBuffer: 500 * 1024
      });
      const truncated = fullDiff.length > 8000 ? fullDiff.slice(0, 8000) + `
[diff truncated]` : fullDiff;
      return `REVIEW_DIFF:Review the following git diff for bugs, security issues, design problems, and improvements. Be concise:

${truncated}`;
    } catch {
      return "Could not read git diff.";
    }
  }
  const lines = [];
  lines.push("");
  lines.push("╔══════════════════════════════════════════╗");
  lines.push("║       Code Review — Pending Changes       ║");
  lines.push("╚══════════════════════════════════════════╝");
  lines.push("");
  const summaryLine = statOutput.trim().split(`
`).pop() || "";
  lines.push(`  Summary: ${summaryLine}`);
  lines.push("");
  let changedFiles = [];
  try {
    changedFiles = execSync2("git diff --name-only", { cwd: wd, encoding: "utf-8", timeout: 1e4 }).trim().split(`
`).filter(Boolean);
  } catch {
    lines.push("  (warning: could not list changed files)");
  }
  lines.push("  Changed files:");
  lines.push("");
  for (const file of changedFiles) {
    const ext = file.split(".").pop()?.toLowerCase() ?? "";
    const icon = getFileIcon(ext);
    lines.push(`  ${icon}  ${file}`);
  }
  lines.push("");
  lines.push("  ── Static Checks ──");
  const warnings = [];
  try {
    const fullDiff = execSync2("git diff", { cwd: wd, encoding: "utf-8", timeout: 1e4, maxBuffer: 500 * 1024 });
    if (fullDiff.includes("TODO") || fullDiff.includes("FIXME") || fullDiff.includes("HACK")) {
      warnings.push("  ● TODOs/FIXMEs/HACKs found in diff");
    }
    const secretPatterns = [/sk-[A-Za-z0-9]{32,}/, /AIza[0-9A-Za-z_-]{32,}/, /ghp_[A-Za-z0-9]{36,}/, /-----BEGIN.*PRIVATE KEY-----/];
    for (const pattern of secretPatterns) {
      if (pattern.test(fullDiff)) {
        warnings.push("  ● Potential secret/credential detected!");
        break;
      }
    }
    if (fullDiff.includes("console.log") || fullDiff.includes("console.debug")) {
      warnings.push("  ● Console statements found");
    }
    if (fullDiff.includes("debugger")) {
      warnings.push("  ● debugger statement found");
    }
  } catch {}
  if (warnings.length > 0) {
    for (const w of warnings)
      lines.push(w);
  } else {
    lines.push("  ● No issues detected.");
  }
  lines.push("");
  lines.push("  For AI model review: /review deep");
  return lines.join(`
`);
}
function getFileIcon(ext) {
  const icons = {
    ts: "[TS]",
    tsx: "[TX]",
    js: "[JS]",
    jsx: "[JX]",
    json: "{ }",
    md: "[MD]",
    css: "[# ]",
    html: "<>",
    yml: "[Y]",
    yaml: "[Y]",
    toml: "[T]",
    sh: "[SH]",
    py: "[PY]",
    rs: "[RS]",
    go: "[GO]",
    java: "[JV]",
    rb: "[RB]"
  };
  return icons[ext] ?? "   ";
}

// src/cli/commands/lint.ts
import { execSync as execSync3 } from "child_process";
import { existsSync as existsSync6 } from "fs";
import { join as join8 } from "path";
function lintCommand(engine) {
  const lines = [];
  lines.push("");
  lines.push("╔══════════════════════════════════════════╗");
  lines.push("║       Lint — Run Code Quality Checks      ║");
  lines.push("╚══════════════════════════════════════════╝");
  lines.push("");
  const wd = engine.config.getWorkingDir();
  const detectors = [
    { name: "ESLint", cmd: "npx eslint --no-color --format compact 2>&1", files: [".eslintrc.js", ".eslintrc.cjs", ".eslintrc.json", ".eslintrc.yaml", ".eslintrc.yml", "eslint.config.js", "eslint.config.mjs", "eslint.config.cjs"] },
    { name: "Biome", cmd: "npx biome check --no-errors-on-unmatched 2>&1", files: ["biome.json", "biome.jsonc"] },
    { name: "Prettier", cmd: "npx prettier --check . 2>&1", files: [".prettierrc", ".prettierrc.json", ".prettierrc.yaml", ".prettierrc.js", "prettier.config.js"] },
    { name: "tsc", cmd: "npx tsc --noEmit 2>&1", files: ["tsconfig.json"] },
    { name: "oxlint", cmd: "npx oxlint 2>&1", files: [".oxlintrc.json", ".oxlint.json"] }
  ];
  let found = false;
  for (const detector of detectors) {
    const hasConfig = detector.files.some((f) => existsSync6(join8(wd, f)));
    if (!hasConfig)
      continue;
    found = true;
    lines.push(`  ── ${detector.name} ──`);
    try {
      const output = execSync3(detector.cmd, {
        cwd: wd,
        encoding: "utf-8",
        timeout: 60000,
        maxBuffer: 500 * 1024,
        shell: process.platform === "win32" ? "cmd.exe" : "/bin/sh"
      });
      const trimmed = output.trim();
      if (trimmed) {
        const filtered = trimmed.split(`
`).filter((l) => l.trim()).slice(0, 30);
        for (const fl of filtered) {
          lines.push(`  ${fl}`);
        }
        if (trimmed.split(`
`).length > 30) {
          lines.push(`  ... (${trimmed.split(`
`).length - 30} more lines)`);
        }
      } else {
        lines.push("  ● No issues found.");
      }
    } catch (err) {
      const e = err;
      const output = (e.stdout || e.stderr || "").trim();
      if (output) {
        const filtered = output.split(`
`).filter((l) => l.trim()).slice(0, 30);
        for (const fl of filtered) {
          lines.push(`  ${fl}`);
        }
        if (output.split(`
`).length > 30) {
          lines.push(`  ... (${output.split(`
`).length - 30} more lines)`);
        }
      } else {
        lines.push(`  ● ${detector.name} found issues (exit code: ${e.status})`);
      }
    }
    lines.push("");
  }
  if (!found) {
    lines.push("  No linter configuration found in this project.");
    lines.push("");
    lines.push("  Try running:");
    lines.push("    npx eslint --init");
    lines.push("    npx biome init");
    lines.push("  or add a tsconfig.json for TypeScript checking.");
  }
  return lines.join(`
`);
}

// src/cli/commands/security.ts
import { execSync as execSync4 } from "child_process";
function securityCommand(engine) {
  const lines = [];
  lines.push("");
  lines.push("╔══════════════════════════════════════════╗");
  lines.push("║       Security Scan                      ║");
  lines.push("╚══════════════════════════════════════════╝");
  lines.push("");
  const wd = engine.config.getWorkingDir();
  const scans = [
    {
      name: "Secret Detection",
      run: () => scanForSecrets(wd)
    },
    {
      name: "Dependency Vulnerabilities",
      run: () => scanDependencies(wd)
    },
    {
      name: "File Permissions",
      run: () => scanFilePermissions(wd)
    },
    {
      name: "Git Exposure",
      run: () => scanGitExposure(wd)
    }
  ];
  let issueCount = 0;
  for (const scan of scans) {
    lines.push(`  ── ${scan.name} ──`);
    const findings = scan.run();
    if (findings.length === 0) {
      lines.push("  ● No issues found.");
    } else {
      for (const finding of findings) {
        lines.push(`  ● ${finding}`);
        issueCount++;
      }
    }
    lines.push("");
  }
  lines.push(`  Total issues: ${issueCount}`);
  if (issueCount === 0) {
    lines.push("  ● All scans passed.");
  }
  return lines.join(`
`);
}
function scanForSecrets(wd) {
  const findings = [];
  const secretPatterns = [
    { name: "GitHub PAT", pattern: /ghp_[A-Za-z0-9]{36,}/ },
    { name: "GitHub OAuth", pattern: /gho_[A-Za-z0-9]{36,}/ },
    { name: "OpenAI API Key", pattern: /sk-(?:proj-)?[A-Za-z0-9_-]{32,}/ },
    { name: "Anthropic API Key", pattern: /sk-ant-[A-Za-z0-9_-]{32,}/ },
    { name: "Google API Key", pattern: /AIza[0-9A-Za-z_-]{32,}/ },
    { name: "AWS Access Key", pattern: /AKIA[0-9A-Z]{16}/ },
    { name: "AWS Secret Key", pattern: /['"][A-Za-z0-9/+]{40}['"]/ },
    { name: "Private Key", pattern: /-----BEGIN (RSA|EC|DSA|OPENSSH)?\s*PRIVATE KEY-----/ },
    { name: "Slack Token", pattern: /xox[baprs]-[A-Za-z0-9-]{10,}/ },
    { name: "JWT Token", pattern: /eyJ[A-Za-z0-9_-]{10,}\.[A-Za-z0-9_-]{10,}\.[A-Za-z0-9_-]{10,}/ }
  ];
  try {
    const diff = execSync4("git diff --unified=0", {
      cwd: wd,
      encoding: "utf-8",
      timeout: 1e4,
      maxBuffer: 200 * 1024
    });
    const addedLines = diff.split(`
`).filter((l) => l.startsWith("+") && !l.startsWith("+++"));
    for (const line of addedLines) {
      for (const sp of secretPatterns) {
        if (sp.pattern.test(line)) {
          findings.push(`${sp.name} pattern detected in diff`);
          break;
        }
      }
    }
  } catch {}
  return findings;
}
function scanDependencies(wd) {
  const findings = [];
  try {
    const result = execSync4("npm audit --json 2>&1 || true", {
      cwd: wd,
      encoding: "utf-8",
      timeout: 30000,
      shell: process.platform === "win32" ? "powershell.exe" : "/bin/sh"
    });
    try {
      const parsed = JSON.parse(result);
      const vulns = parsed?.vulnerabilities ?? parsed?.metadata?.vulnerabilities ?? {};
      const counts = {};
      if (parsed?.metadata?.vulnerabilities) {
        for (const [key, val] of Object.entries(parsed.metadata.vulnerabilities)) {
          const n = val;
          if (n > 0)
            counts[key] = n;
        }
      }
      if (Object.keys(counts).length > 0) {
        for (const [severity, count] of Object.entries(counts)) {
          findings.push(`${count} ${severity} severity vulnerabilities`);
        }
      }
    } catch {
      if (result.includes("vulnerabilities")) {
        findings.push("Vulnerabilities found — run 'npm audit' for details");
      }
    }
  } catch {}
  return findings;
}
function scanFilePermissions(wd) {
  const findings = [];
  try {
    const result = execSync4('find . -type f -perm /111 -name "*.sh" 2>/dev/null | head -5', {
      cwd: wd,
      encoding: "utf-8",
      timeout: 5000,
      shell: process.platform === "win32" ? "powershell.exe" : "/bin/sh"
    });
    const scripts = result.trim().split(`
`).filter(Boolean);
    if (scripts.length >= 5) {
      findings.push(`${scripts.length} executable scripts found in project`);
    }
  } catch {}
  return findings;
}
function scanGitExposure(wd) {
  const findings = [];
  try {
    const result = execSync4("git ls-files --cached .env .env.local .env.production 2>/dev/null || true", {
      cwd: wd,
      encoding: "utf-8",
      timeout: 5000,
      shell: process.platform === "win32" ? "powershell.exe" : "/bin/sh"
    });
    const tracked = result.trim().split(`
`).filter(Boolean);
    for (const t of tracked) {
      findings.push(`Environment file tracked in git: ${t}`);
    }
  } catch {}
  return findings;
}

